from pydantic import BaseModel, field_validator, ValidationError


class User(BaseModel):
    username: str
    email: str
    age: int

    @field_validator('username')
    @classmethod
    def username_must_be_alphanumeric(cls, v: str) -> str:
        if not v.isalnum():
            raise ValueError('must be alphanumeric')
        return v.lower()  # normalize to lowercase

    @field_validator('email')
    @classmethod
    def email_must_contain_at(cls, v: str) -> str:
        if '@' not in v:
            raise ValueError('must contain @')
        return v.lower()

    @field_validator('age')
    @classmethod
    def age_must_be_reasonable(cls, v: int) -> int:
        if not 0 < v < 150:
            raise ValueError('must be between 1 and 149')
        return v


# Valid input -- note username gets lowercased
user = User(username="Alice123", email="ALICE@Example.com", age=30)
print(f"{user.username}, {user.email}, {user.age}")

