# Practical example: shipping cost depends on weight and destination
class ShippingOrder(BaseModel):
    weight_kg: float
    destination: str
    shipping_cost: float

    @model_validator(mode='after')
    def validate_shipping_cost(self) -> Self:
        min_cost = self.weight_kg * 2.0
        if self.destination == 'international':
            min_cost *= 3
        if self.shipping_cost < min_cost:
            raise ValueError(
                f'shipping_cost must be >= {min_cost} for '
                f'{self.weight_kg}kg {self.destination}'
            )
        return self

order = ShippingOrder(weight_kg=5.0, destination="domestic", shipping_cost=15.0)
print(f"Order: {order.weight_kg}kg, ${order.shipping_cost}")

# Expected Output:
# 2024-01-01 to 2024-12-31
# Error: Value error, end_date must be after start_date
# Password set: 9 chars
# Error: Value error, passwords do not match
# Order: 5.0kg, $15.0

