from pydantic import BaseModel, computed_field


class Rectangle(BaseModel):
    width: float
    height: float

    @computed_field
    @property
    def area(self) -> float:
        return self.width * self.height

    @computed_field
    @property
    def perimeter(self) -> float:
        return 2 * (self.width + self.height)

    @computed_field
    @property
    def is_square(self) -> bool:
        return self.width == self.height


rect = Rectangle(width=5.0, height=3.0)

# Computed fields accessible as properties
print(f"Area: {rect.area}")
print(f"Perimeter: {rect.perimeter}")
print(f"Is square: {rect.is_square}")

# Computed fields appear in serialization
print(f"\nmodel_dump: {rect.model_dump()}")

# Computed fields in JSON Schema
schema = Rectangle.model_json_schema()
print(f"\nSchema properties: {list(schema['properties'].keys())}")


# Practical example: user with full name
class User(BaseModel):
    first_name: str
    last_name: str
    hourly_rate: float
    hours_worked: float

    @computed_field
    @property
    def full_name(self) -> str:
        return f"{self.first_name} {self.last_name}"

    @computed_field
    @property
    def total_pay(self) -> float:
        return round(self.hourly_rate * self.hours_worked, 2)


